#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS{
	il ll read(){
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=gc();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x){
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x){
		write(x);
		puts("");
	}
}
using NP phigrOS;
CI MAXN=1e5+5;
int n,h[MAXN],rk[MAXN],L[MAXN],R[MAXN],c[MAXN],ans;
vector<int>s;
int lb(int x){return x&-x;}
void add(int x,int v){for(;x<=n;x+=lb(x))c[x]+=v;}
int qry(int x){int r=0;for(;x;x-=lb(x))r+=c[x];return r;}
int fd(int x){return lower_bound(s.begin(),s.end(),x)-s.begin()+1;}
signed main(void)
{
	n=read();
	FOR(i,1,n)
    {
		h[i]=read();
		s.pb(h[i]);
	}
	sort(s.begin(),s.end());
	s.erase(unique(s.begin(),s.end()),s.end());
	FOR(i,1,n)rk[i]=fd(h[i]);
	FOR(i,1,n)
    {
		L[i]=i-1-qry(rk[i]);
		add(rk[i],1);
	}
	cl(c);
	ROF(i,n,1)
    {
		R[i]=n-i-qry(rk[i]);
		add(rk[i],1);
	}
	FOR(i,1,n)
    {
		int mx=max(L[i],R[i]);
		int mn=min(L[i],R[i]);
		if(mx>2*mn)
        {
			ans++;
		}
	}
	writeln(ans);
	return false;
}
